// Risk scoring: 0-100 (higher = more at risk)
// Weights: days_since_activity 40%, open_cases_30d 30%, no_open_opp 15%, no_recent_meeting 15%

const results = [];
const today = new Date();

for (const item of $input.all()) {
  const account = item.json;

  // --- Days since last activity (weight: 40%) ---
  let daysSinceActivity = 999; // assume max risk if null
  if (account.LastActivityDate) {
    const lastActivity = new Date(account.LastActivityDate);
    daysSinceActivity = Math.floor((today - lastActivity) / (1000 * 60 * 60 * 24));
  }
  // Score 0-40: 0 days = 0 pts, 60+ days = 40 pts
  const activityScore = Math.min(40, (daysSinceActivity / 60) * 40);

  // --- Open cases in last 30 days (weight: 30%) ---
  const openCases = account.Cases ? account.Cases.records || [] : [];
  const openCaseCount = openCases.length;
  // Score 0-30: 0 cases = 0 pts, 5+ cases = 30 pts
  const caseScore = Math.min(30, openCaseCount * 6);

  // --- No open opportunity (weight: 15%) ---
  const openOpps = account.Opportunities ? account.Opportunities.records || [] : [];
  const hasOpenOpp = openOpps.length > 0;
  const oppScore = hasOpenOpp ? 0 : 15;

  // --- No recent meeting/activity logged in 14 days (weight: 15%) ---
  const noRecentMeeting = daysSinceActivity > 14;
  const meetingScore = noRecentMeeting ? 15 : 0;

  // --- Total risk score ---
  const riskScore = Math.round(activityScore + caseScore + oppScore + meetingScore);

  // --- Risk factors for Slack message ---
  const riskFactors = [];
  if (daysSinceActivity >= 30) riskFactors.push(`No activity in ${daysSinceActivity} days`);
  if (openCaseCount > 0) riskFactors.push(`${openCaseCount} open case(s) in last 30 days`);
  if (!hasOpenOpp) riskFactors.push('No open renewal or expansion opportunity');
  if (noRecentMeeting) riskFactors.push('No logged meeting in 14+ days');

  // --- Risk label ---
  let riskLabel = '🟢 Low';
  if (riskScore >= 75) riskLabel = '🔴 Critical';
  else if (riskScore >= 60) riskLabel = '🟠 High';
  else if (riskScore >= 40) riskLabel = '🟡 Medium';

  results.push({
    json: {
      accountId: account.Id,
      accountName: account.Name,
      ownerId: account.OwnerId,
      ownerName: account['Owner.Name'] || account.Owner?.Name || 'Unknown CSM',
      daysSinceActivity,
      openCaseCount,
      hasOpenOpp,
      riskScore,
      riskLabel,
      riskFactors,
      sfLink: `https://login.salesforce.com/${account.Id}`
    }
  });
}

// Sort by risk score descending
results.sort((a, b) => b.json.riskScore - a.json.riskScore);

return results;
